module RefModule(
	input clk,
	input clear,
	input load,
	input [7:0] data_in,
	output [7:0] data_out);reg [7:0] reg_data;

	  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt)
		if (clear) reg_data <= 8'b0;
		else if (load) reg_data <= data_in;

	assign data_out = reg_data;

endmodule
